/** @generated —
 * Feature test generator - creates unit test stubs for a feature
 */

import { resolve } from 'node:path';
import { writeFile, mkdir } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import { toPascalCase } from './utils.js';

export interface GeneratorResult {
  path: string;
  content: string;
}

/**
 * Generate a unit test file for the business logic layer
 */
export async function generateFeatureTest(
  entityName: string,
  root: string
): Promise<GeneratorResult> {
  const pascalName = toPascalCase(entityName);
  const dir = resolve(root, `packages/business-logic/src/${entityName}`);
  const filePath = resolve(dir, `validate-${entityName}.test.ts`);

  if (!existsSync(dir)) {
    await mkdir(dir, { recursive: true });
  }

  const content = `/**
 * @generated by @flusk/cli - flusk generate feature ${entityName}
 * Unit tests for ${pascalName} validation
 */

import { describe, it, expect } from 'vitest';
import { validate${pascalName} } from './validate-${entityName}.function.js';

describe('validate${pascalName}', () => {
  it('returns valid for a well-formed entity', () => {
    const result = validate${pascalName}({
      // TODO: Add valid entity fields
    });
    expect(result.valid).toBe(true);
    expect(result.errors).toHaveLength(0);
  });

  it('returns errors for an empty entity', () => {
    const result = validate${pascalName}({});
    // TODO: Update assertion once validation is implemented
    expect(result).toBeDefined();
  });
});
`;

  await writeFile(filePath, content, 'utf-8');

  return {
    path: `packages/business-logic/src/${entityName}/validate-${entityName}.test.ts`,
    content,
  };
}
